mapper.insert:
insert into tbl_member (
    email, password, nickname, real_name, birth_date, phone_number, profile_image,
    role, status, creator_verified, seller_verified, creator_tier, follower_count, following_count, gallery_count
) values (
    #{email}, #{password}, #{nickname}, #{realName}, #{birthDate}, #{phoneNumber}, #{profileImage},
    #{role}, #{status}, #{creatorVerified}, #{sellerVerified}, #{creatorTier}, #{followerCount}, #{followingCount}, #{galleryCount}
)

mapper.select:
select exists(
    select 1
    from tbl_member
    where email = #{email}
)

select exists(
    select 1
    from tbl_member
    where nickname = #{nickname}
)
